    // Implement pagination
    const startIndex = (pageNum - 1) * limitNum;
    const paginatedUsers = users.slice(startIndex, startIndex + limitNum);

    res.setHeader('Content-Type', 'application/json');
    res.json({
      data: paginatedUsers,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total: users.length
      }
    });
  } catch (error) {
    next(error);
  }
});

