   - No global error handler middleware
   - Unhandled errors will expose sensitive stack traces in production
   - No try-catch blocks or error recovery

6. **No Rate Limiting**
   - No protection against brute force or DoS attacks
   - Endpoints can be hammered with unlimited requests

7. **No Input Sanitization**
   - If query parameters are later added, they won't be sanitized
   - Risk of XSS if user input is returned in responses

8. **Sensitive Data Exposure**
   - Hardcoded user data with email addresses
   - No encryption or hashing of sensitive information

9. **Missing Helmet.js Protection**
   - Should use `helmet()` middleware for security headers

10. **No Logging/Monitoring**
    - No request logging for audit trails
    - No error tracking or monitoring

### 🟢 **Recommended Improvements**

Here's an improved version with security best practices:

```javascript
// Enhanced application with security best practices

const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const mongoSanitize = require('express-mongo-sanitize');
const validator = require('validator');

const app = express();

// ✅ Security middleware - Apply helmet for security headers
app.use(helmet());

// ✅ Rate limiting - Prevent DoS attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests, please try again later.',
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false,
});
app.use(limiter);

// ✅ Body parser with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// ✅ Data sanitization - Prevent NoSQL injection
app.use(mongoSanitize());

// ✅ Health check endpoint (public, no sensitive data)
app.get('/health', (req, res) => {
  try {
    res.json({ status: 'ok', timestamp: new Date().toISOString() });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// ✅ Protected users endpoint with input validation
app.get('/users', validateApiKey, (req, res) => {
  try {
    // Validate query parameters (if any)
    const { limit = 10, offset = 0 } = req.query;

    if (!Number.isInteger(parseInt(limit)) || parseInt(limit) < 1 || parseInt(limit) > 100) {
      return res.status(400).json({ error: 'Invalid limit parameter' });
    }
    if (!Number.isInteger(parseInt(offset)) || parseInt(offset) < 0) {
      return res.status(400).json({ error: 'Invalid offset parameter' });
    }

    // Return sanitized data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json({
      data: users.slice(offset, offset + limit),
      total: users.length,
      limit: parseInt(limit),
      offset: parseInt(offset),
    });
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// ✅ Authentication middleware
function validateApiKey(req, res, next) {
  const apiKey = req.headers['x-api-key'];

  if (!apiKey) {
    return res.status(401).json({ error: 'Missing API key' });
  }

  // Validate API key format and value
  if (!validator.isUUID(apiKey) && apiKey.length < 32) {
    return res.status(401).json({ error: 'Invalid API key' });
  }

  // In production, validate against database
  const validKeys = [process.env.API_KEY]; // Load from environment
  if (!validKeys.includes(apiKey)) {
    return res.status(403).json({ error: 'Unauthorized' });
  }

  next();
}

// ✅ 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Endpoint not found' });
});

// ✅ Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't leak error details in production
  const isDevelopment = process.env.NODE_ENV === 'development';
  const errorResponse = {
    error: 'Internal server error',
    ...(isDevelopment && { details: err.message }),
  };

  res.status(err.status || 500).json(errorResponse);
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

